import React, { useState } from "react";
import Navbar from "../../components/Navbar";
import "../../App.css";

function AdminStockManagement() {
  const [stock, setStock] = useState([
    { name: "Milk", quantity: 20, expiry: "2026-01-10", price: 30 },
    { name: "Maggi", quantity: 40, expiry: "2026-03-01", price: 15 },
  ]);

  /* ================= CSV PARSER ================= */
  const parseCSV = (text) => {
    const lines = text.trim().split("\n");
    const headers = lines[0].split(",").map((h) => h.trim());

    return lines.slice(1).map((line) => {
      const values = line.split(",").map((v) => v.trim());
      let obj = {};
      headers.forEach((h, i) => {
        obj[h] = values[i];
      });

      return {
        name: obj.name,
        quantity: Number(obj.quantity),
        expiry: obj.expiry,
        price: Number(obj.price),
      };
    });
  };

  /* ================= CSV UPLOAD HANDLER ================= */
  const handleCSVUpload = (e) => {
    const file = e.target.files[0];
    if (!file) return;

    if (!file.name.endsWith(".csv")) {
      alert("Please upload a valid CSV file");
      return;
    }

    const reader = new FileReader();
    reader.onload = (event) => {
      const csvText = event.target.result;
      const parsedData = parseCSV(csvText);
      setStock((prev) => [...prev, ...parsedData]);
    };

    reader.readAsText(file);
  };

  return (
    <>
      <Navbar variant="dashboard" />

      <div className="container">
        {/* HEADER */}
        <div className="card">
          <h2>Admin – Stock Management</h2>
          <p className="note">
            Manage inventory manually or upload stock using CSV
          </p>
        </div>

        {/* CSV UPLOAD INSIDE STOCK PAGE */}
        <div className="card">
          <h3>Upload Stock (CSV)</h3>

          <input
            type="file"
            accept=".csv"
            onChange={handleCSVUpload}
          />

          <p className="note" style={{ marginTop: "10px" }}>
            CSV format: <br />
            <code>name,quantity,expiry,price</code>
          </p>
        </div>

        {/* STOCK TABLE */}
        <div className="card">
          <h3>Current Inventory</h3>

          {stock.length === 0 ? (
            <p className="note">No stock available</p>
          ) : (
            <table>
              <thead>
                <tr>
                  <th>Product</th>
                  <th>Quantity</th>
                  <th>Expiry</th>
                  <th>Price</th>
                </tr>
              </thead>
              <tbody>
                {stock.map((item, index) => (
                  <tr key={index}>
                    <td>{item.name}</td>
                    <td>{item.quantity}</td>
                    <td>{item.expiry}</td>
                    <td>₹{item.price}</td>
                  </tr>
                ))}
              </tbody>
            </table>
          )}
        </div>
      </div>
    </>
  );
}

export default AdminStockManagement;
